--- a/bin/cli.js
+++ b/bin/cli.js
@@ -10,12 +10,14 @@ const USAGE = `Usage: bench-cli <command> [options]
 Commands:
   hello [--name NAME]        Print a greeting (default name: "world")
   version                    Print the CLI version from package.json
+  payout --input PATH        Print payout totals for ledger events
   --help, -h                 Show this help

 Examples:
   bench-cli hello
   bench-cli hello --name alice
   bench-cli version
+  bench-cli payout --input ledger-events.json
 `;

 function readPackageVersion() {
@@ -35,6 +37,166 @@ function parseNameFlag(argv) {
   return value;
 }

+function writePayoutError(error) {
+  process.stderr.write(`${JSON.stringify(error)}\n`);
+  process.exit(2);
+}
+
+function readPayoutInput(argv) {
+  const inputIndex = argv.indexOf('--input');
+  const inputPath = argv[inputIndex + 1];
+
+  if (inputIndex === -1 || !inputPath || inputPath.startsWith('-')) {
+    writePayoutError({ error: 'unreadable_input' });
+  }
+
+  let rawInput;
+  try {
+    rawInput = fs.readFileSync(inputPath, 'utf8');
+  } catch {
+    writePayoutError({ error: 'unreadable_input' });
+  }
+
+  try {
+    return JSON.parse(rawInput);
+  } catch {
+    writePayoutError({ error: 'invalid_json' });
+  }
+}
+
+function validateEvent(event, index) {
+  if (!event || typeof event !== 'object' || Array.isArray(event)) {
+    writePayoutError({ error: 'invalid_event', index });
+  }
+  if (typeof event.id !== 'string') {
+    writePayoutError({ error: 'missing_id', index });
+  }
+  if (typeof event.merchant_id !== 'string') {
+    writePayoutError({ error: 'missing_merchant_id', index });
+  }
+  if (!['charge', 'refund', 'dispute'].includes(event.type)) {
+    writePayoutError({ error: 'unknown_type', index });
+  }
+  if (!Number.isInteger(event.amount_cents) || event.amount_cents <= 0) {
+    writePayoutError({ error: 'invalid_amount_cents', index });
+  }
+}
+
+function hasSameEventContent(first, second) {
+  return first.id === second.id
+    && first.merchant_id === second.merchant_id
+    && first.type === second.type
+    && first.amount_cents === second.amount_cents;
+}
+
+function uniqueEvents(events) {
+  const eventsById = new Map();
+  const unique = [];
+
+  events.forEach((event, index) => {
+    validateEvent(event, index);
+    const priorEvent = eventsById.get(event.id);
+    if (priorEvent) {
+      if (!hasSameEventContent(priorEvent, event)) {
+        writePayoutError({ error: 'conflicting_duplicate', id: event.id });
+      }
+      return;
+    }
+    eventsById.set(event.id, event);
+    unique.push(event);
+  });
+
+  return unique;
+}
+
+function loadPayoutRules() {
+  const rulesPath = path.join(__dirname, '..', 'data', 'payout-rules.json');
+  return JSON.parse(fs.readFileSync(rulesPath, 'utf8'));
+}
+
+function createMerchant(merchantId) {
+  return {
+    merchant_id: merchantId,
+    gross_charge_cents: 0,
+    refund_cents: 0,
+    dispute_cents: 0,
+    processing_fee_cents: 0,
+    dispute_fee_cents: 0,
+  };
+}
+
+function calculatePayout(events, rules) {
+  const merchantsById = new Map();
+
+  for (const event of events) {
+    let merchant = merchantsById.get(event.merchant_id);
+    if (!merchant) {
+      merchant = createMerchant(event.merchant_id);
+      merchantsById.set(event.merchant_id, merchant);
+    }
+
+    if (event.type === 'charge') {
+      merchant.gross_charge_cents += event.amount_cents;
+      merchant.processing_fee_cents += Math.round(
+        event.amount_cents * rules.processing_fee_percent / 100,
+      ) + rules.fixed_fee_cents;
+    } else if (event.type === 'refund') {
+      merchant.refund_cents += event.amount_cents;
+    } else {
+      merchant.dispute_cents += event.amount_cents;
+      merchant.dispute_fee_cents += rules.dispute_fee_cents;
+    }
+  }
+
+  const merchants = Array.from(merchantsById.values(), (merchant) => {
+    const netBeforeReserve = merchant.gross_charge_cents
+      - merchant.refund_cents
+      - merchant.dispute_cents
+      - merchant.processing_fee_cents
+      - merchant.dispute_fee_cents;
+    let reserveCents = netBeforeReserve > 0
+      ? Math.round(netBeforeReserve * rules.reserve_percent / 100)
+      : 0;
+    let payoutCents = netBeforeReserve - reserveCents;
+
+    if (payoutCents > 0 && payoutCents < rules.minimum_payout_cents) {
+      reserveCents += payoutCents;
+      payoutCents = 0;
+    }
+
+    return {
+      ...merchant,
+      reserve_cents: reserveCents,
+      payout_cents: payoutCents,
+    };
+  });
+
+  return {
+    total_payout_cents: merchants.reduce((total, merchant) => total + merchant.payout_cents, 0),
+    total_processing_fee_cents: merchants.reduce(
+      (total, merchant) => total + merchant.processing_fee_cents,
+      0,
+    ),
+    total_dispute_fee_cents: merchants.reduce(
+      (total, merchant) => total + merchant.dispute_fee_cents,
+      0,
+    ),
+    total_reserve_cents: merchants.reduce((total, merchant) => total + merchant.reserve_cents, 0),
+    merchants,
+  };
+}
+
