+  const input = readPayoutInput(argv);
+  if (!input || !Array.isArray(input.events)) {
+    writePayoutError({ error: 'missing_events' });
+  }
+
+  const rules = loadPayoutRules();
+  const result = calculatePayout(uniqueEvents(input.events), rules);
+  process.stdout.write(`${JSON.stringify(result)}\n`);
+}
