const { test } = require('node:test');
const assert = require('node:assert');
const { execFileSync } = require('node:child_process');
const fs = require('node:fs');
const os = require('node:os');
const path = require('node:path');

const CLI = path.join(__dirname, '..', 'bin', 'cli.js');

function run(args) {
  return execFileSync('node', [CLI, ...args], { encoding: 'utf8' });
}

function runFailure(args) {
  let failure;
  try {
    run(args);
  } catch (error) {
    failure = error;
  }
  assert.ok(failure, 'expected the CLI command to fail');
  return failure;
}

test('hello default', () => {
  const out = run(['hello']);
  assert.match(out, /Hello, world!/);
});

test('hello with --name', () => {
  const out = run(['hello', '--name', 'alice']);
  assert.match(out, /Hello, alice!/);
});

test('version prints package version', () => {
  const out = run(['version']);
  assert.match(out, /\d+\.\d+\.\d+/);
});

test('payout prints per-merchant totals after deduplicating events', (t) => {
  const fixtureDirectory = fs.mkdtempSync(path.join(os.tmpdir(), 'bench-cli-'));
  t.after(() => fs.rmSync(fixtureDirectory, { recursive: true, force: true }));
  const inputPath = path.join(fixtureDirectory, 'ledger-events.json');
  fs.writeFileSync(inputPath, JSON.stringify({
    events: [
      { id: 'charge-a', merchant_id: 'merchant-a', type: 'charge', amount_cents: 10000 },
      { id: 'refund-a', merchant_id: 'merchant-a', type: 'refund', amount_cents: 1000 },
      { id: 'dispute-a', merchant_id: 'merchant-a', type: 'dispute', amount_cents: 500 },
      { id: 'charge-b', merchant_id: 'merchant-b', type: 'charge', amount_cents: 500 },
      { id: 'charge-b', merchant_id: 'merchant-b', type: 'charge', amount_cents: 500 },
    ],
  }));

  const output = JSON.parse(run(['payout', '--input', inputPath]));
  assert.deepEqual(output, {
    total_payout_cents: 6012,
    total_processing_fee_cents: 365,
    total_dispute_fee_cents: 1500,
    total_reserve_cents: 1123,
    merchants: [
      {
        merchant_id: 'merchant-a',
        gross_charge_cents: 10000,
        refund_cents: 1000,
        dispute_cents: 500,
        processing_fee_cents: 320,
        dispute_fee_cents: 1500,
        reserve_cents: 668,
        payout_cents: 6012,
      },
      {
        merchant_id: 'merchant-b',
        gross_charge_cents: 500,
        refund_cents: 0,
        dispute_cents: 0,
        processing_fee_cents: 45,
        dispute_fee_cents: 0,
        reserve_cents: 455,
        payout_cents: 0,
      },
    ],
  });
});

test('payout reports validation failures as a single JSON error', (t) => {
  const fixtureDirectory = fs.mkdtempSync(path.join(os.tmpdir(), 'bench-cli-'));
  t.after(() => fs.rmSync(fixtureDirectory, { recursive: true, force: true }));
  const inputPath = path.join(fixtureDirectory, 'ledger-events.json');
  fs.writeFileSync(inputPath, JSON.stringify({
    events: [{ id: 'unknown-type', merchant_id: 'merchant-a', type: 'transfer', amount_cents: 100 }],
  }));

  const failure = runFailure(['payout', '--input', inputPath]);
  const stderr = String(failure.stderr);
  const error = JSON.parse(stderr);

  assert.equal(failure.status, 2);
  assert.equal(String(failure.stdout), '');
  assert.ok(error.error);
  assert.equal(stderr, `${JSON.stringify(error)}\n`);
});

